ControlPropertyState.AutoRuleBindingString:
Switch(ThisItem.'Action Type', 
"Site Induction", 
Set(varInductionForm, true),

"RAMs", 
Set(varRAMS, true);, 
"Misc", 
Set(varMiscAction, true);
);

Set(varActionRecord, ThisItem);

Set(
    varCurrentShiftID,
    Text(ThisItem.'Shift ID')
);
Clear(col_EquipmentLocations);
Clear(col_EquipmentLocationsItems);
Clear(col_EquipmentLocationsItems_Display);
Clear(col_FanOffPressures);
Clear(col_FanOffPressures_Display);
Switch(
    ThisItem.'Action Type',
    "Site Induction",
    Set(
        varActionRecord,
        LookUp(
            col_EngineerActionList,
            ActionGUID = ThisItem.ShiftActionID
        )
    );
    Set(
        varCurrentSite,
        LookUp(
            BESA_Shifts,
            'Shift ID' = ThisItem.'Shift ID'
        ).'Site LookUp'
    );
    Set(
        varSiteRecord,
        LookUp(
            BESA_SiteInductions,
            'Engineer LookUp'.BESA_EngineerList = GUID(varStaffViewBESAID) && 'Site LookUp'.'Site ID' = varActionRecord.'Site LookUp'.'Site ID' && 'Induction Status' = "Completed" && 'Expiry Date' >= Today()
        )
    );
    Set(
        varInductionForm,
        true
    ),
    "RAMs",
    Set(
        varActionRecord,
        ThisItem
    );
    Set(
        varCurrentShiftID,
        Text(ThisItem.'Shift ID')
    );
    ClearCollect(
        col_SelectedSignOffElements,
        ForAll(
            Filter(
                col_EngineerActionList,
                Text('Shift ID') = varCurrentShiftID && 'Action Type' = "Service" && !IsBlank('Booking Element LookUp'.BESA_BookingElement) && CountRows(
                    Filter(
                        BESA_Documents,
                        'Document Type' = "RAMS" && 'Direct Related GUID' = Text('Booking Element LookUp'.'Booking Service Lookup'.BESA_BookingService)
                    )
                ) > 0
            ),
            {
                ElementName: 'Booking Element LookUp'.'Element LookUp'.'Element Name',
                BookingElement: 'Booking Element LookUp'.BESA_BookingElement,
                ActionGUID: ActionGUID
            }
        )
    );
    Set(
        varRAMSServiceGUID,
        Text(
            LookUp(
                BESA_BookingElements,
                BESA_BookingElement = First(col_SelectedSignOffElements).BookingElement
            ).'Booking Service Lookup'.BESA_BookingService
        )
    );
    ClearCollect(
        col_RAMSDocuments,
        Filter(
            BESA_Documents,
            'Document Type' = "RAMS" && 'Direct Related GUID' = varRAMSServiceGUID
        )
    );
    Set(
        varSignOffActivity,
        Concat(
            Filter(
                col_EngineerActionList,
                ActionGUID in col_SelectedSignOffElements.ActionGUID
            ),
            'Booking Element LookUp'.'Order Service LookUp'.Division & " - " & 'Booking Element LookUp'.'Order Service LookUp'.Service,
            Char(10)
        )
    );
    Navigate(scrRAMSSignOff),
    "Adhoc",
    Set(
        varMiscAction,
        true
    );
    Set(
        varActionRecord,
        LookUp(
            col_EngineerActionList,
            ActionGUID = ThisItem.ShiftActionID
        )
    ),
    "Activity",
    Set(
        varActionRecord,
        LookUp(
            col_EngineerActionList,
            ActionGUID = ThisItem.ShiftActionID
        )
    );
    Set(
        varActivityRecord,
        LookUp(
            BESA_Activities,
            'Shift GUID' = ThisItem.'Shift ID'
        )
    );
    Set(
        varCompleteActivity,
        true
    ),
    "Risk Assessment",
    Set(
        varActionRecord,
        LookUp(
            col_EngineerActionList,
            ActionGUID = ThisItem.ShiftActionID
        )
    );
    Set(
        varRAMSJobNum,
        ThisItem.'Booking LookUp'.'Booking ID'
    );
    Set(
        varRAMSSiteName,
        ThisItem.'Site LookUp'.Name
    );
    Set(
        varRAMSProNum,
        LookUp(
            BESA_Bookings,
            BESA_Booking = ThisItem.'Booking LookUp'.BESA_Booking
        ).'Order LookUp'.OrderReference
    );
    Set(
        varRAMSActivities,
        Concat(
            Filter(
                col_EngineerActionList,
                'Action Name' = "Service" && 'Shift ID' = ThisItem.'Shift ID'
            ),
            'Booking Element LookUp'.'Order Service LookUp'.Division & " - " & 'Booking Element LookUp'.'Order Service LookUp'.Service,
            Char(10)
        )
    );
    Set(
        varRAMSElements,
        Concat(
            Filter(
                col_EngineerActionList,
                'Action Name' = "Service" && 'Shift ID' = ThisItem.'Shift ID'
            ),
            'Booking Element LookUp'.'Element LookUp'.'Element Name',
            Char(10)
        )
    );
    Navigate(Screen_EngineerRiskAssessment),
    "Service",
    If(
        ThisItem.'Booking Element LookUp'.'Order Service LookUp'.'Service LookUp'.'Test Type' <> Blank(),
        /* 
            =============================================
                    PERM TEST INITIALISATION
            =============================================*/
        // 1️⃣ Set current shift
        Set(
            varCurrentShiftID,
            Text(ThisItem.'Shift ID')
        );
        // 2️⃣ Store Test Type from Service record
        Set(
            varServiceTestType,
            Text(ThisItem.'Booking Element LookUp'.'Order Service LookUp'.'Service LookUp'.'Test Type')
        );
        // 3️⃣ Shared default JSON for Pre & Post test data
        Set(
            varDefaultTestData,
            JSON(
                {
                    ExternalTemperature: 0,
                    CorrectedExternalTemperature: 0,
                    BarometricPressure: 0,
                    CorrectedBarometricPressure: 0,
                    Windspeed: 0,
                    CorrectedWindspeed: 0,
                    AvgPositiveDp: 0,
                    AvgNegativeDp: 0,
                    AvgTotalDp: 0,
                    InternalTemperatures: [
                        {
                            RowNumber: 1,
                            Location: "",
                            Temperature: 0,
                            CorrectedTemperature: 0,
                            Complete: false
                        }
                    ],
                    FanOffPressures: []
                }
            )
        );
        // 4️⃣ Check if a test already exists for this booking + shift
        Set(
            varExistingTest,
            LookUp(
                BESA_Tests,
                'Booking Element LookUp'.BESA_BookingElement = ThisItem.'Booking Element LookUp'.BESA_BookingElement && 'Shift LookUp'.'Shift ID' = varCurrentShiftID && 'Test Status' = "Pending"
            )
        );
        // 5️⃣ Create new BESA_Test or use existing
        If(
            IsBlank(varExistingTest),
            Set(
                varNewTestID,
                Text(GUID())
            );
            Set(
                varActionRecord,
                Patch(
                    BESA_Tests,
                    Defaults(BESA_Tests),
                    {
                        'Booking Element LookUp': ThisItem.'Booking Element LookUp',
                        'Envelope LookUp': LookUp(
                            BESA_Envelopes,
                            'Booking Element LookUp'.BESA_BookingElement = ThisItem.'Booking Element LookUp'.BESA_BookingElement
                        ),
                        'Shift LookUp': LookUp(
                            BESA_Shifts,
                            'Shift ID' = varCurrentShiftID
                        ),
                        'Client LookUp': ThisItem.'Client LookUp',
                        'Booking LookUp': ThisItem.'Booking LookUp',
                        'Site LookUp': ThisItem.'Site LookUp',
                        'Test Status': "Pending",
                        'Test Number': 1,
                        //TempSealingData:    JSON({TempSealingStatus: "", Questions: []}),
                        'Section Status': JSON(
                            {
                                TestDetails: "Pending",
                                Envelope: "Pending",
                                ReportExport: "Pending"
                            }
                        ),
                        'Test Info': JSON(
                            {
                                TypeAB: "",
                                TestType: "",
                                YearBuilt: 0
                            }
                        )
                    }
                )
            );
            Set(
                varCurrentActionID,
                ThisItem.ShiftActionID
            );
            Set(
                varTestViewMode,
                false
            ),
            Set(
                varActionRecord,
                varExistingTest
            )
        );
        // ── Run 1 — always created ──
        Set(
            varExistingTestRun,
            LookUp(
                BESA_TestRuns,
                'Test LookUp'.BESA_Test = varActionRecord.BESA_Test && 'Test No' = 1
            )
        );
        If(
            IsBlank(varExistingTestRun),
            Set(
                varTestRunRecord,
                Patch(
                    BESA_TestRuns,
                    Defaults(BESA_TestRuns),
                    {
                        'Test LookUp': LookUp(
                            BESA_Tests,
                            BESA_Test = varActionRecord.BESA_Test
                        ),
                        'Test No': 1,
                        RunSelected: true,
                        'Test Name': "Run 1",
                        'Test Status': "Pending",
                        PreTestData: varDefaultTestData,
                        PostTestData: varDefaultTestData,
                        TestMetaData: JSON(
                            {
                                DateTimeTest: "",
                                Engineer: "",
                                TestType: /*If(
                                                                      varServiceTestType = "Air Test",
                                                                      "Depressurisation",
                                                                      "Pressurisation"
                                                                  ),*/"Depressurisation",
                                EngineerLocation: "",
                                OpeningTargetPA: 0,
                                ClosingTargetPA: 0,
                                PressureStep: 0,
                                TargetPoints: 0
                            }
                        ),
                        TempSealingData: JSON(
                            {
                                TempSealingStatus: "",
                                Questions: []
                            }
                        ),
                        EquipmentLocations: JSON([]),
                        EquipmentItems: JSON([]),
                        SummaryResults: JSON({})
                    }
                )
            ),
             // Auto-repair: if TestType was wiped to "" by a stale save, restore it now
            If(
                IsBlank(Text(ParseJSON(varExistingTestRun.TestMetaData).TestType)) || Text(ParseJSON(varExistingTestRun.TestMetaData).TestType) = "",
                Patch(
                    BESA_TestRuns,
                    varExistingTestRun,
                    {
                        TestMetaData: JSON(
                            {
                                DateTimeTest: Text(ParseJSON(varExistingTestRun.TestMetaData).DateTimeTest),
                                Engineer: Text(ParseJSON(varExistingTestRun.TestMetaData).Engineer),
                                TestType: "Depressurisation",
                                //If(varServiceTestType = "Air Test", "Depressurisation", "Pressurisation"),
EngineerLocation: Text(ParseJSON(varExistingTestRun.TestMetaData).EngineerLocation),
                                OpeningTargetPA: Value(Text(ParseJSON(varExistingTestRun.TestMetaData).OpeningTargetPA)),
                                ClosingTargetPA: Value(Text(ParseJSON(varExistingTestRun.TestMetaData).ClosingTargetPA)),
                                PressureStep: Value(Text(ParseJSON(varExistingTestRun.TestMetaData).PressureStep)),
                                TargetPoints: Value(Text(ParseJSON(varExistingTestRun.TestMetaData).TargetPoints))
                            }
                        )
                    }
                )
            );
            Set(
                varTestRunRecord,
                varExistingTestRun
            )
        );
        // ── Run 2 — only for 2-run test types ──
        If(
            /*varServiceTestType = "Plenum Air Leakage Test Report" ||
            varServiceTestType = "Air Change Rate Test Report"    ||
            varServiceTestType = "Air Test Report",*/
            varServiceTestType = "Plenum Test" || varServiceTestType = "Isolation Room Air Test" || varServiceTestType = "PassivHaus Test",
            //|| varServiceTestType = "Smoke Shaft Test" ||
            //varServiceTestType = "Air Test",
            Set(
                varExistingTestRun2,
                LookUp(
                    BESA_TestRuns,
                    'Test LookUp'.BESA_Test = varActionRecord.BESA_Test && 'Test No' = 2
                )
            );
            If(
                IsBlank(varExistingTestRun2),
                Set(
                    varTestRunRecord2,
                    Patch(
                        BESA_TestRuns,
                        Defaults(BESA_TestRuns),
                        {
                            'Test LookUp': LookUp(
                                BESA_Tests,
                                BESA_Test = varActionRecord.BESA_Test
                            ),
                            'Test No': 2,
                            RunSelected: true,
                            'Test Name': "Run 2",
                            'Test Status': "Pending",
                            PreTestData: varDefaultTestData,
                            PostTestData: varDefaultTestData,
                            TestMetaData: JSON(
                                {
                                    DateTimeTest: "",
                                    Engineer: "",
                                    TestType: "Pressurisation",
                                    EngineerLocation: "",
                                    OpeningTargetPA: 0,
                                    ClosingTargetPA: 0,
                                    PressureStep: 0,
                                    TargetPoints: 0
                                }
                            ),
                            TempSealingData: JSON(
                                {
                                    TempSealingStatus: "",
                                    Questions: []
                                }
                            ),
                            EquipmentLocations: JSON([]),
                            EquipmentItems: JSON([]),
                            SummaryResults: JSON({})
                        }
                    )
                ),
                // Auto-repair: if TestType was wiped to "" restore it as Pressurisation (Run 2 is always Pressurisation)
                If(
                    IsBlank(Text(ParseJSON(varExistingTestRun2.TestMetaData).TestType)) || Text(ParseJSON(varExistingTestRun2.TestMetaData).TestType) = "",
                    Patch(
                        BESA_TestRuns,
                        varExistingTestRun2,
                        {
                            TestMetaData: JSON(
                                {
                                    DateTimeTest: Text(ParseJSON(varExistingTestRun2.TestMetaData).DateTimeTest),
                                    Engineer: Text(ParseJSON(varExistingTestRun2.TestMetaData).Engineer),
                                    TestType: "Pressurisation",
                                    EngineerLocation: Text(ParseJSON(varExistingTestRun2.TestMetaData).EngineerLocation),
                                    OpeningTargetPA: Value(Text(ParseJSON(varExistingTestRun2.TestMetaData).OpeningTargetPA)),
                                    ClosingTargetPA: Value(Text(ParseJSON(varExistingTestRun2.TestMetaData).ClosingTargetPA)),
                                    PressureStep: Value(Text(ParseJSON(varExistingTestRun2.TestMetaData).PressureStep)),
                                    TargetPoints: Value(Text(ParseJSON(varExistingTestRun2.TestMetaData).TargetPoints))
                                }
                            )
                        }
                    )
                );
                Set(
                    varTestRunRecord2,
                    varExistingTestRun2
                )
            )
        );
        // 6️⃣ Build collection for app use
        ClearCollect(
            col_TestRun,
            ForAll(
                Filter(
                    BESA_TestRuns,
                    'Test LookUp'.BESA_Test = varActionRecord.BESA_Test
                ) As run,
                {
                    TestID: run.BESA_TestRun,
                    TestName: run.'Test Name',
                    RunSelected: run.RunSelected,
                    TestNo: run.'Test No',
                    TestStatus: run.'Test Status',
                    TestMetaData: ParseJSON(run.TestMetaData),
                    PreTestData: ParseJSON(run.PreTestData),
                    PostTestData: ParseJSON(run.PostTestData),
                    //TempSealingData: ParseJSON(run.TempSealingData),
                    EquipmentLocations: If(
                        IsBlank(run.EquipmentLocations) || run.EquipmentLocations = "[]",
                        Table(
                            {
                                Location: "",
                                SetNumber: "",
                                TubeIdentifier: 0,
                                Engineer: Blank(),
                                RowNumber: 1
                            }
                        ),
                        ForAll(
                            ParseJSON(run.EquipmentLocations) As equipLoc,
                            {
                                Location: Text(equipLoc.Location),
                                SetNumber: Text(equipLoc.SetNumber),
                                TubeIdentifier: Value(equipLoc.TubeIdentifier),
                                Engineer: equipLoc.Engineer,
                                RowNumber: Value(equipLoc.RowNumber)
                            }
                        )
                    ),
                    EquipmentItems: If(
                        IsBlank(run.EquipmentItems) || run.EquipmentItems = "[]",
                        Table(
                            {
                                SetNumber: "",
                                SetLocationRef: 0,
                                EquipmentType: "",
                                SerialNumber: "",
                                Selected: false,
                                ManometerType: "",
                                FloorNo: 0,
                                LinkedFan: Blank(),
                                LinkedFan_Range: Blank()
                            }
                        ),
                        ForAll(
                            ParseJSON(run.EquipmentItems) As equipItem,
                            {
                                SetNumber: Text(equipItem.SetNumber),
                                SetLocationRef: Value(equipItem.SetLocationRef),
                                EquipmentType: Text(equipItem.EquipmentType),
                                SerialNumber: Text(equipItem.SerialNumber),
                                Selected: Boolean(equipItem.Selected),
                                ManometerType: Text(equipItem.ManometerType),
                                FloorNo: Value(equipItem.FloorNo),
                                LinkedFan: equipItem.LinkedFan,
                                LinkedFan_Range: equipItem.LinkedFan_Range
                            }
                        )
                    ),
                    SummaryResults: ParseJSON(run.SummaryResults)
                }
            )
        );
        // 7️⃣ Parse Section Status and Test Info for UI
        Set(
            varSectionStatus,
            ParseJSON(varActionRecord.'Section Status')
        );
        Set(
            varTestInfo,
            ParseJSON(varActionRecord.'Test Info')
        );
        // 8️⃣ Build col_PermTestMenu
        ClearCollect(
            col_PermTestMenu,
            {
                MenuLabel: "Test Details",
                MenuCategory: "Test Details",
                Status: Text(varSectionStatus.TestDetails),
                Sort: 1,
                DisplayLabel: "Test Details " & If(
                    Text(varSectionStatus.TestDetails) = "Complete",
                    "✓",
                    "⚠️"
                )
            },
            {
                MenuLabel: "Envelope",
                MenuCategory: "Envelope",
                Status: Text(varSectionStatus.Envelope),
                Sort: 2,
                DisplayLabel: "Envelope " & If(
                    Text(varSectionStatus.Envelope) = "Complete",
                    "✓",
                    "⚠️"
                )
            },
            {
                MenuLabel: "Temp Sealing",
                MenuCategory: "Temp Sealing",
                Sort: 3,
                Status: "Pending",
                DisplayLabel: "Temp Sealing " & If(
                    Text(ParseJSON(varActionRecord.TempSealingData).TempSealingStatus) = "Complete",
                    "✓",
                    "⚠️"
                ),
                MenuIcon: Icon.CheckBadge
            }
        );
        ForAll(
            Filter(
                col_TestRun,
                !IsBlank(TestNo) && TestNo > 0
            ),
            Collect(
                col_PermTestMenu,
                {
                    MenuLabel: "Test Data - Run " & Text(ThisRecord.TestNo),
                    MenuCategory: "Test Data",
                    Status: Text(ThisRecord.TestStatus),
                    Sort: 3 + Value(ThisRecord.TestNo),
                    DisplayLabel: "Test Data - Run " & Text(ThisRecord.TestNo) & " " & If(
                        ThisRecord.TestStatus = "Complete",
                        "✓",
                        "⚠️"
                    )
                }
            )
        );
        Collect(
            col_PermTestMenu,
            {
                MenuLabel: "Report & Export",
                MenuCategory: "Report & Export",
                Status: Text(varSectionStatus.ReportExport),
                Sort: 999,
                DisplayLabel: "Report & Export " & If(
                    Text(varSectionStatus.ReportExport) = "Complete",
                    "✓",
                    "⚠️"
                )
            }
        );
        ClearCollect(
            col_LocationOptions,
            {Value: "Inside"},
            {Value: "Outside"}
        );
        Set(
            varSelectedRunCount,
            Sum(
                col_TestRun,
                If(
                    RunSelected,
                    1,
                    0
                )
            )
        );
        Set(
            varPressurisationSelected,
            Sum(
                col_TestRun,
                If(
                    RunSelected && Text(TestMetaData.TestType) = "Pressurisation",
                    1,
                    0
                )
            ) >= 1
        );
        Set(
            varDepressurisationSelected,
            Sum(
                col_TestRun,
                If(
                    RunSelected && Text(TestMetaData.TestType) = "Depressurisation",
                    1,
                    0
                )
            ) >= 1
        );
        Set(
            varSelectedTestRunID,
            First(
                SortByColumns(
                    col_TestRun,
                    "TestNo",
                    SortOrder.Ascending
                )
            ).TestID
        );
        // 9️⃣ Navigate to Perm Test Screen
        Navigate(Screen_EngineerPermTest_V2_1),
        // Non-Perm Test
        Set(
            varActionRecord,
            LookUp(
                col_EngineerActionList,
                ActionGUID = ThisItem.ShiftActionID
            )
        );
        Set(
            varServiceRecord,
            LookUp(
                BESA_BookingElements,
                BESA_BookingElement = ThisItem.'Booking Element LookUp'.BESA_BookingElement
            )
        );
        Set(
            varTestViewMode,
            ThisItem.'Action Status' = "Pending Completion"
        );
        Set(
            varServiceAction,
            true
        )
    )
);

ClearCollect(col_EngineerActionList, 
{ 
    'Site LookUp':First(col_Sites), 
    'Action Type': "", 
    'Action Name': "", 
    'Booking LookUp':First(col_Bookings), 
    'Induction LookUp':First(col_SiteInductions), 
    'Action Status':"", 
    'RAMS LookUp':First(col_RiskAssesments), 
    'Element LookUp':First(col_ElementList), 
    'Booking Element LookUp':First(col_BookingElement),
    'Shift ID': ""
});

Clear(col_EngineerActionList);

//Site Information

ClearCollect(col_ShiftListCheck, AddColumns(RenameColumns(ShowColumns(Filter(col_ShiftList, 'Technician GUID' = varStaffViewID.StaffID, 'Shift Date' = dateEngineerSelectedView_1.SelectedDate, 'Shift Type' = "Booking"), 'Shift Type', BookingID, 'Shift Date', 'Technician GUID'), BookingID, BookingTempID), 'Site LookUp', LookUp(col_BookingsSchedule, BookingID = BookingTempID, 'Site LookUp'))); 

ForAll(col_ShiftListCheck As shiftListCheck, 
    //IsBlank(LookUp(col_SiteInductions, 'Staff LookUp'.StaffID = shiftListCheck.'Technician GUID' && 'Site LookUp'.SiteID = shiftListCheck.'Site LookUp'.SiteID && 'Induction Status' = "Completed")), 
    Collect(col_EngineerActionList, 
    { 
        'Booking LookUp':LookUp(col_Bookings, BookingReference = shiftListCheck.BookingTempID), 
        'Site LookUp':LookUp(col_Sites, SiteID = shiftListCheck.'Site LookUp'.SiteID), 
        'Induction LookUp':LookUp(col_SiteInductions, 'Staff LookUp'.StaffID = shiftListCheck.'Technician GUID' && 'Site LookUp'.SiteID = shiftListCheck.'Site LookUp'.SiteID && 'Induction Status' = "Completed"),
        'Action Status': If(IsBlank(LookUp(col_SiteInductions, 'Staff LookUp'.StaffID = shiftListCheck.'Technician GUID' && 'Site LookUp'.SiteID = shiftListCheck.'Site LookUp'.SiteID && 'Induction Status' = "Completed")), "Pending", "Not Required"),
        'Action Type':"Site Induction", 
        'Action Name':"Site Induction Form"
    }); 
    Collect(col_EngineerActionList, 
    { 
        'Booking LookUp':LookUp(col_Bookings, BookingReference = shiftListCheck.BookingTempID), 
        'Site LookUp':LookUp(col_Sites, SiteID = shiftListCheck.'Site LookUp'.SiteID), 
        //'Induction LookUp':LookUp(col_SiteInductions, 'Staff LookUp'.StaffID = shiftListCheck.'Technician GUID' && 'Site LookUp'.SiteID = shiftListCheck.'Site LookUp'.SiteID && 'Induction Status' = "Completed"),
        'Action Type':"RAMs", 
        'Action Name':"RAMs Form",
        'Action Status':If(IsBlank(LookUp(col_RiskAssesments, 'Staff LookUp'.StaffID = shiftListCheck.'Technician GUID' && 'Site LookUp'.SiteID = shiftListCheck.'Site LookUp'.SiteID && 'Assesment Date' = dateEngineerSelectedView_1.SelectedDate)), "Pending", If(IsBlank(LookUp(col_RiskAssesments, 'Staff LookUp'.StaffID = shiftListCheck.'Technician GUID' && 'Site LookUp'.SiteID = shiftListCheck.'Site LookUp'.SiteID && 'Assesment Date' = dateEngineerSelectedView_1.SelectedDate, 'Assesment Status' = "Completed")), "Drafted", "Completed")),
        'RAMS LookUp':LookUp(col_RiskAssesments, 'Staff LookUp'.StaffID = shiftListCheck.'Technician GUID' && 'Site LookUp'.SiteID = shiftListCheck.'Site LookUp'.SiteID && 'Assesment Date' = dateEngineerSelectedView_1.SelectedDate)
    }); 
    );


    ClearCollect(col_ShiftListCheck, AddColumns(RenameColumns(ShowColumns(Filter(col_ShiftList, 'Technician GUID' = varStaffViewID.StaffID, 'Shift Date' = dateEngineerSelectedView_1.SelectedDate, 'Shift Type' = "Booking"), 'Shift Type', BookingID, 'Shift Date', 'Technician GUID', 'Shift ID'), BookingID, BookingTempID), 'Site LookUp', LookUp(col_BookingsSchedule, BookingID = BookingTempID, 'Site LookUp'))); 


//Booking Elements for each Shift
ClearCollect(col_BookingElementCheck, Filter(col_BookingElement, 'Shift ID' in col_ShiftListCheck.'Shift ID'));

ForAll(col_BookingElementCheck As itemBookingElement, 
Collect(col_EngineerActionList, 
    { 
        'Booking LookUp':LookUp(col_Bookings, BookingReference = itemBookingElement.BookingID), 
        'Site LookUp':LookUp(col_Sites, SiteID = itemBookingElement.'Site LookUp'.SiteID), 
        //'Induction LookUp':LookUp(col_SiteInductions, 'Staff LookUp'.StaffID = shiftListCheck.'Technician GUID' && 'Site LookUp'.SiteID = shiftListCheck.'Site LookUp'.SiteID && 'Induction Status' = "Completed"),
        'Action Status': "Pending",
        'Action Type':"Service", 
        'Action Name':"Service", 
        'Element LookUp':itemBookingElement.'Element LookUp', 
        'Booking Element LookUp':LookUp(col_BookingElement, BookingElementID = itemBookingElement.BookingElementID), 
        'Shift ID':itemBookingElement.'Shift ID'
    }));


//Non Booking Shifts
ClearCollect(col_ShiftListNonBookingCheck, RenameColumns(ShowColumns(Filter(col_ShiftList, 'Technician GUID' = varStaffViewID.StaffID, 'Shift Date' = dateEngineerSelectedView_1.SelectedDate, 'Shift Type' <> "Booking"), 'Shift Type', BookingID, 'Shift Date', 'Technician GUID', 'Shift ID'), BookingID, BookingTempID));

ForAll(col_ShiftListNonBookingCheck As itemNonBookingItem, 
Collect(col_EngineerActionList,
{ 
    'Action Status': "Pending", 
    'Action Type':"Misc", 
    'Action Name':itemNonBookingItem.'Shift Type', 
